+fn build_simple_streaming_group_by_outputs(
+    result_descriptors: &[GroupByColumn],
+    having_expr: Option<&Expr>,
+    order_by: &[OrderingTerm],
+    expanded_columns: &[ResultColumn],
+    group_collations: &[Option<String>],
+) -> Option<Vec<SimpleStreamingGroupByOutput>> {
+    if having_expr.is_some()
+        || group_collations.iter().any(Option::is_some)
+        || order_by
+            .iter()
+            .any(|term| resolve_order_term_idx(&term.expr, expanded_columns).is_none())
+    {
+        return None;
+    }
+
+    result_descriptors
+        .iter()
+        .map(simple_streaming_group_by_output_from_descriptor)
+        .collect()
+}
+
+fn simple_streaming_group_by_output_from_descriptor(
+    descriptor: &GroupByColumn,
+) -> Option<SimpleStreamingGroupByOutput> {
+    match descriptor {
+        GroupByColumn::Plain(expr) => {
+            if expr_contains_agg(expr) || expr_has_any_subquery(expr) {
+                None
+            } else {
+                Some(SimpleStreamingGroupByOutput::Plain(expr.clone()))
+            }
+        }
+        GroupByColumn::Agg {
+            name,
+            arg_col,
+            arg_expr,
+            distinct,
+            separator,
+            separator_expr,
+            filter,
+            collation,
+            order_by,
+        } => {
+            if *distinct
+                || filter.is_some()
+                || !order_by.is_empty()
+                || separator.is_some()
+                || separator_expr.is_some()
+                || (matches!(name.as_str(), "min" | "max") && collation.is_some())
+                || arg_expr
+                    .as_ref()
+                    .is_some_and(|expr| expr_has_any_subquery(expr))
+            {
+                return None;
+            }
+
+            match name.as_str() {
+                "count" if arg_col.is_none() && arg_expr.is_none() => {
+                    Some(SimpleStreamingGroupByOutput::CountStar)
+                }
+                "count" => Some(SimpleStreamingGroupByOutput::CountValue {
+                    arg_col: *arg_col,
+                    arg_expr: arg_expr.clone(),
+                }),
+                "sum" => Some(SimpleStreamingGroupByOutput::SumValue {
+                    arg_col: *arg_col,
+                    arg_expr: arg_expr.clone(),
+                }),
+                "avg" => Some(SimpleStreamingGroupByOutput::AvgValue {
+                    arg_col: *arg_col,
+                    arg_expr: arg_expr.clone(),
+                }),
+                "min" => Some(SimpleStreamingGroupByOutput::MinValue {
+                    arg_col: *arg_col,
+                    arg_expr: arg_expr.clone(),
+                }),
+                "max" => Some(SimpleStreamingGroupByOutput::MaxValue {
+                    arg_col: *arg_col,
+                    arg_expr: arg_expr.clone(),
+                }),
+                _ => None,
+            }
+        }
+    }
+}
