+impl SimpleStreamingGroupByState {
+    fn new(representative_row: Vec<SqliteValue>, outputs: &[SimpleStreamingGroupByOutput]) -> Self {
+        Self {
+            representative_row,
+            accumulators: outputs
+                .iter()
+                .map(SimpleStreamingGroupByOutput::initial_accumulator)
