+fn simple_streaming_group_by_value(
+    arg_col: Option<usize>,
+    arg_expr: Option<&Expr>,
+    row: &[SqliteValue],
+    col_map: &[(String, String, bool)],
+) -> Result<SqliteValue> {
+    if let Some(idx) = arg_col {
+        Ok(row.get(idx).cloned().unwrap_or(SqliteValue::Null))
+    } else if let Some(expr) = arg_expr {
+        eval_join_expr(expr, row, col_map)
+    } else {
+        Ok(SqliteValue::Null)
+    }
+}
+
+fn update_simple_streaming_group_by_state(
+    state: &mut SimpleStreamingGroupByState,
+    outputs: &[SimpleStreamingGroupByOutput],
+    row: &[SqliteValue],
+    col_map: &[(String, String, bool)],
+) -> Result<()> {
+    for (output, accumulator) in outputs.iter().zip(state.accumulators.iter_mut()) {
+        match (output, accumulator) {
+            (SimpleStreamingGroupByOutput::Plain(_), SimpleStreamingGroupByAccumulator::Plain) => {}
+            (
+                SimpleStreamingGroupByOutput::CountStar,
+                SimpleStreamingGroupByAccumulator::Count(count),
+            ) => {
+                *count += 1;
+            }
+            (
