+                SimpleStreamingGroupByAccumulator::Count(count),
+            ) => {
+                let value =
+                    simple_streaming_group_by_value(*arg_col, arg_expr.as_deref(), row, col_map)?;
+                if !matches!(value, SqliteValue::Null) {
+                    *count += 1;
+                }
+            }
+            (
+                SimpleStreamingGroupByOutput::SumValue { arg_col, arg_expr },
+                SimpleStreamingGroupByAccumulator::Sum {
+                    sum,
+                    err,
+                    int_sum,
+                    has_int,
+                    all_int,
+                    int_overflowed,
+                    saw_value,
+                },
+            ) => {
+                let value =
+                    simple_streaming_group_by_value(*arg_col, arg_expr.as_deref(), row, col_map)?;
+                if matches!(value, SqliteValue::Null) {
+                    continue;
+                }
+                *saw_value = true;
+                match value {
+                    SqliteValue::Integer(n) => {
+                        *has_int = true;
+                        if !*int_overflowed {
+                            match int_sum.checked_add(n) {
+                                Some(next) => *int_sum = next,
+                                None => *int_overflowed = true,
+                            }
+                        }
+                        kbn_step(sum, err, n as f64);
+                    }
+                    SqliteValue::Float(f) => {
+                        *all_int = false;
+                        kbn_step(sum, err, f);
+                    }
+                    other => {
+                        *all_int = false;
+                        kbn_step(sum, err, other.to_float());
+                    }
+                }
+            }
+            (
+                SimpleStreamingGroupByOutput::AvgValue { arg_col, arg_expr },
+                SimpleStreamingGroupByAccumulator::Avg { sum, err, count },
+            ) => {
+                let value =
+                    simple_streaming_group_by_value(*arg_col, arg_expr.as_deref(), row, col_map)?;
+                if matches!(value, SqliteValue::Null) {
+                    continue;
+                }
+                match value {
+                    SqliteValue::Integer(n) => kbn_step(sum, err, n as f64),
+                    SqliteValue::Float(f) => kbn_step(sum, err, f),
+                    other => kbn_step(sum, err, other.to_float()),
+                }
+                *count += 1;
+            }
+            (
+                SimpleStreamingGroupByOutput::MinValue { arg_col, arg_expr },
+                SimpleStreamingGroupByAccumulator::Min(current),
+            ) => {
+                let value =
+                    simple_streaming_group_by_value(*arg_col, arg_expr.as_deref(), row, col_map)?;
+                if matches!(value, SqliteValue::Null) {
+                    continue;
+                }
+                match current {
+                    Some(existing)
+                        if cmp_sqlite_values(&value, existing) != std::cmp::Ordering::Less => {}
+                    _ => *current = Some(value),
+                }
+            }
+            (
+                SimpleStreamingGroupByOutput::MaxValue { arg_col, arg_expr },
+                SimpleStreamingGroupByAccumulator::Max(current),
+            ) => {
+                let value =
+                    simple_streaming_group_by_value(*arg_col, arg_expr.as_deref(), row, col_map)?;
+                if matches!(value, SqliteValue::Null) {
+                    continue;
+                }
+                match current {
+                    Some(existing)
+                        if cmp_sqlite_values(&value, existing) != std::cmp::Ordering::Greater => {}
+                    _ => *current = Some(value),
+                }
+            }
+            _ => {
+                return Err(FrankenError::internal(
+                    "simple streaming GROUP BY output/accumulator mismatch",
+                ));
+            }
+        }
+    }
+    Ok(())
+}
