+fn finalize_simple_streaming_group_by_row(
+    state: &SimpleStreamingGroupByState,
+    outputs: &[SimpleStreamingGroupByOutput],
+    col_map: &[(String, String, bool)],
+) -> Vec<SqliteValue> {
+    outputs
+        .iter()
+        .zip(state.accumulators.iter())
+        .map(|(output, accumulator)| match (output, accumulator) {
+            (SimpleStreamingGroupByOutput::Plain(expr), _) => {
+                eval_join_expr(expr, &state.representative_row, col_map)
+                    .unwrap_or(SqliteValue::Null)
+            }
+            (_, SimpleStreamingGroupByAccumulator::Count(count)) => SqliteValue::Integer(*count),
+            (
+                SimpleStreamingGroupByOutput::SumValue { .. },
+                SimpleStreamingGroupByAccumulator::Sum {
+                    sum,
+                    err,
+                    int_sum,
+                    has_int,
+                    all_int,
+                    int_overflowed,
+                    saw_value,
+                },
+            ) => {
+                if !*saw_value {
+                    SqliteValue::Null
+                } else if *has_int && *all_int && !*int_overflowed {
+                    SqliteValue::Integer(*int_sum)
+                } else {
+                    SqliteValue::Float(*sum + *err)
+                }
+            }
+            (
+                SimpleStreamingGroupByOutput::AvgValue { .. },
+                SimpleStreamingGroupByAccumulator::Avg { sum, err, count },
+            ) => {
+                if *count == 0 {
+                    SqliteValue::Null
+                } else {
+                    SqliteValue::Float((*sum + *err) / *count as f64)
+                }
+            }
+            (_, SimpleStreamingGroupByAccumulator::Min(value))
+            | (_, SimpleStreamingGroupByAccumulator::Max(value)) => {
+                value.clone().unwrap_or(SqliteValue::Null)
+            }
+            _ => SqliteValue::Null,
+        })
+        .collect()
+}
